type UnusualMerchantCandidatesRow struct {
	ID          uuid.UUID       `json:"id"`
	Amount      decimal.Decimal `json:"amount"`
	Date        stdtime.Time    `json:"date"`
	MerchantKey *string         `json:"merchant_key"`
	Merchant    string          `json:"merchant"`
}

// Merchants whose first-ever transaction in the household falls on or after the
// cutoff — i.e. merchants that only just started appearing. One representative
// (most recent) qualifying spend per merchant is returned so the event can link
// to a real transaction. A merchant this alert already flagged is skipped via
// the payload merchant_key, so a merchant is announced once, not once per new
// charge.
func (q *Queries) UnusualMerchantCandidates(ctx context.Context, arg UnusualMerchantCandidatesParams) ([]UnusualMerchantCandidatesRow, error) {
	rows, err := q.db.Query(ctx, unusualMerchantCandidates,
		arg.HouseholdID,
		arg.Date,
		arg.Amount,
		arg.AlertID,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []UnusualMerchantCandidatesRow{}
	for rows.Next() {
		var i UnusualMerchantCandidatesRow
		if err := rows.Scan(
			&i.ID,
			&i.Amount,
			&i.Date,
			&i.MerchantKey,
			&i.Merchant,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

const updateAlert = `-- name: UpdateAlert :one
UPDATE alerts
SET config = $3, enabled = $4, push = $5, updated_at = now()
WHERE id = $1 AND household_id = $2
RETURNING id, household_id, type, config, enabled, created_at, updated_at, push
`

type UpdateAlertParams struct {
	ID          uuid.UUID `json:"id"`
	HouseholdID uuid.UUID `json:"household_id"`
	Config      []byte    `json:"config"`
	Enabled     bool      `json:"enabled"`
	Push        bool      `json:"push"`
}

func (q *Queries) UpdateAlert(ctx context.Context, arg UpdateAlertParams) (Alert, error) {
	row := q.db.QueryRow(ctx, updateAlert,
		arg.ID,
		arg.HouseholdID,
		arg.Config,
		arg.Enabled,
		arg.Push,
	)
	var i Alert
	err := row.Scan(
		&i.ID,
		&i.HouseholdID,
		&i.Type,
		&i.Config,
		&i.Enabled,
		&i.CreatedAt,
		&i.UpdatedAt,
		&i.Push,
	)
	return i, err
}
